import { createContext, useContext, useState } from "react";

const AuthContext = createContext();

const defaultUsers = [
  {
    id: 1,
    name: "Admin FoodMart",
    tenDangNhap: "admin",
    email: "admin@foodmart.vn",
    password: "admin123",
    diaChi: "Hà Nội",
    soDienThoai: "0901234567",
    ngayDangKy: "2024-01-01T00:00:00.000Z",
    role: "admin",
  },
  {
    id: 2,
    name: "Demo User",
    tenDangNhap: "demouser",
    email: "demo@foodmart.vn",
    password: "123456",
    diaChi: "Hồ Chí Minh",
    soDienThoai: "0987654321",
    ngayDangKy: "2024-01-02T00:00:00.000Z",
    role: "user",
  },
];

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [users, setUsers] = useState(defaultUsers);

  const login = (email, password) => {
    const found = users.find(
      (u) => u.email === email && u.password === password
    );
    if (found) { setUser(found); return true; }
    return false;
  };

  const register = (data) => {
    const exists = users.find((u) => u.email === data.email);
    if (exists) return false;
    const newUser = {
      id: Date.now(),
      name: data.name,
      tenDangNhap: data.tenDangNhap || data.email.split("@")[0],
      email: data.email,
      password: data.password,
      diaChi: data.diaChi || "",
      soDienThoai: data.soDienThoai || "",
      ngayDangKy: new Date().toISOString(),
      role: "user",
    };
    setUsers((prev) => [...prev, newUser]);
    setUser(newUser);
    return true;
  };

  const updateProfile = (updated) => {
    setUser((prev) => ({ ...prev, ...updated }));
    setUsers((prev) =>
      prev.map((u) => (u.id === updated.id ? { ...u, ...updated } : u))
    );
  };

  const logout = () => setUser(null);
  const isAdmin = user?.role === "admin";

  return (
    <AuthContext.Provider value={{ user, users, login, register, logout, isAdmin, updateProfile }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  return useContext(AuthContext);
}
